class Solution:
    def countTestedDevices(self, batteryPercentages: List[int]) -> int:
        tested = 0
        decrement = 0

        for battery in batteryPercentages:
            current = battery - decrement
            if current > 0:
                tested += 1
                decrement += 1  # This simulates the decrement on subsequent devices
            # Else, do nothing, as the device is not tested

        return tested
